import React, { useState } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import { Alert } from '../../components/UI';
import LiveMap from '../../components/LiveMap';
import { STATUS_META } from '../../data/mockData';

export default function CleanerPortal() {
  const { complaints, updateComplaint } = useApp();
  const [activeTab, setActiveTab] = useState('JOBS');
  const [selected, setSelected] = useState(null);

  const myTasks = complaints.filter(c => c.vendor?.id === 'v1'); 
  const visibleTasks = myTasks.filter(t => activeTab === 'HISTORY' ? t.status === 'COMPLETED' : t.status !== 'COMPLETED');

  const advanceStatus = (task) => {
    if (task.status === 'ACCEPTED' || task.status === 'IN_PROGRESS') {
      const nextStatus = task.status === 'ACCEPTED' ? 'IN_PROGRESS' : 'COMPLETED';
      const clrStatus = nextStatus === 'IN_PROGRESS' ? 'CLEANING' : 'DONE';
      
      const payload = { status: nextStatus, cleanerStatus: clrStatus };
      if (nextStatus === 'COMPLETED') {
        payload.resolutionMins = 35;
      }
      
      updateComplaint(task.id, payload);
      if (selected?.id === task.id) setSelected(p => ({ ...p, ...payload }));
    }
  };

  const navItems = [
    { key: 'JOBS', label: 'Field Assignments', icon: '🧹', count: myTasks.filter(t => t.status !== 'COMPLETED').length },
    { key: 'HISTORY', label: 'Archive Logs', icon: '📁', count: 0 }
  ];

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#F7F9FC', overflow: 'hidden', fontFamily: 'sans-serif' }}>
      <Sidebar 
        title="Field Force App" subtitle="CleanRail Taskforce" 
        navItems={navItems} activeTab={activeTab} onTabChange={setActiveTab}
        footerUser={{ name: 'Dinesh Rao', role: 'Station Cleaner', initials: 'DR', avatarColor: '#2E7D32' }}
      />

      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: 20 }}>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, flex: 1, overflow: 'hidden' }}>
          
          <div style={{ overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 10 }}>
            {visibleTasks.length === 0 ? (
              <Alert type="blue">No active cleaning drills assigned in this quadrant.</Alert>
            ) : (
              visibleTasks.map(t => {
                const meta = STATUS_META[t.status] || { label: t.status, bg: '#eee', color: '#000' };
                return (
                  <div key={t.id} onClick={() => setSelected(t)} style={{ background: '#fff', padding: 14, borderRadius: 10, border: `1px solid ${selected?.id === t.id ? '#1565C0' : '#DDE3E9'}`, cursor: 'pointer' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                      <span style={{ fontSize: 11, fontFamily: 'monospace', color: '#7A8FA6' }}>{t.customTicketId}</span>
                      <span style={{ fontSize: 10, background: meta.bg, color: meta.color, padding: '2px 6px', borderRadius: 4, fontWeight: 700 }}>{meta.label}</span>
                    </div>
                    <div style={{ fontWeight: 700, fontSize: 14 }}>{t.emoji} {t.area}</div>
                    <div style={{ fontSize: 11, color: '#546E7A' }}>{t.station?.name}</div>
                  </div>
                );
              })
            )}
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
            {selected ? (
              <div style={{ background: '#fff', padding: 16, borderRadius: 12, border: '1px solid #DDE3E9', display: 'flex', flexDirection: 'column', gap: 12, flex: 1 }}>
                <div style={{ fontWeight: 700, fontSize: 14 }}>Target Coordinates</div>
                <LiveMap singlePin={true} singleCoords={{ lat: selected.lat, lng: selected.lng }} height="180px" />
                <div style={{ background: '#F7F9FC', padding: 12, borderRadius: 8, fontSize: 12 }}><strong>Notes:</strong> {selected.desc}</div>
                
                <div style={{ marginTop: 'auto' }}>
                  {selected.status === 'ACCEPTED' && (
                    <button onClick={() => advanceStatus(selected)} style={{ width: '100%', background: '#4527A0', color: '#fff', padding: 12, border: 'none', borderRadius: 8, fontWeight: 700, cursor: 'pointer' }}>🚀 Start Work (IN_PROGRESS)</button>
                  )}
                  {selected.status === 'IN_PROGRESS' && (
                    <button onClick={() => advanceStatus(selected)} style={{ width: '100%', background: '#2E7D32', color: '#fff', padding: 12, border: 'none', borderRadius: 8, fontWeight: 700, cursor: 'pointer' }}>✅ Complete Task</button>
                  )}
                  {selected.status === 'COMPLETED' && (
                    <div style={{ textAlign: 'center', color: '#2E7D32', fontWeight: 800, padding: 10, background: '#E8F5E9', borderRadius: 8, fontSize: 11 }}>✨ SYNCHRONIZED WITH COMMAND SYSTEM</div>
                  )}
                </div>
              </div>
            ) : <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#fff', borderRadius: 12, border: '1px solid #DDE3E9', color: '#7A8FA6', fontSize: 13 }}>Select an entry from the ledger.</div>}
          </div>

        </div>
      </div>
    </div>
  );
}
